@app.route('/api/auth/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    username = sanitize_string(data.get('username'), max_length=30)
    email = sanitize_string(data.get('email'), max_length=255)
    password = data.get('password', '')
    display_name = sanitize_string(data.get('display_name', ''), max_length=100)

    # Validation
    if not validate_username(username):
        return jsonify({'error': 'Invalid username. Use 3-30 alphanumeric characters or underscores.'}), 400
    if not validate_email(email):
        return jsonify({'error': 'Invalid email format'}), 400
    if not password or len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400
    if len(password) > 128:
        return jsonify({'error': 'Password too long'}), 400

    # Check for existing user
    if users_collection.find_one({'$or': [{'email': email}, {'username': username}]}):
        return jsonify({'error': 'Username or email already exists'}), 409

    user_doc = {
        'username': username,
        'email': email.lower(),
        'password_hash': generate_password_hash(password),
        'display_name': display_name or username,
        'role': 'viewer',  # Default role: viewer, editor, admin
        'bio': '',
        'avatar_url': '',
        'preferences': {},
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'is_active': True
    }

    result = users_collection.insert_one(user_doc)
    user_id = str(result.inserted_id)

    token, expires_at = create_session(user_id)
    log_audit(user_id, 'user_registered')

    return jsonify({
        'message': 'User registered successfully',
        'user_id': user_id,
        'token': token,
        'expires_at': expires_at.isoformat()
    }), 201


@app.route('/api/auth/login', methods=['POST'])
def login():
    """Authenticate a user and return a session token."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = sanitize_string(data.get('email', ''), max_length=255)
    password = data.get('password', '')

    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400

    user = users_collection.find_one({'email': email.lower()})
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401

    if not user.get('is_active', True):
        return jsonify({'error': 'Account is deactivated'}), 403

    token, expires_at = create_session(str(user['_id']))
    log_audit(str(user['_id']), 'user_login')

    return jsonify({
        'message': 'Login successful',
        'user_id': str(user['_id']),
        'token': token,
        'expires_at': expires_at.isoformat()
    }), 200


