def create_document():
    """Create a new document."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    title = sanitize_string(data.get('title'), max_length=200)
    content = sanitize_string(data.get('content'), max_length=100000)
    category = sanitize_string(data.get('category', ''), max_length=50)
    tags = data.get('tags', [])

    if not title:
        return jsonify({'error': 'Title is required'}), 400
    if not content:
        return jsonify({'error': 'Content is required'}), 400

    # Validate tags
    if not isinstance(tags, list):
        return jsonify({'error': 'Tags must be a list'}), 400
    sanitized_tags = []
    for tag in tags[:20]:  # Max 20 tags
        sanitized_tag = sanitize_string(str(tag), max_length=50)
        if sanitized_tag:
            sanitized_tags.append(sanitized_tag.lower())

    doc = {
        'title': title,
        'content': content,
        'category': category,
        'tags': sanitized_tags,
        'author_id': request.current_user['_id'],
        'author_name': request.current_user.get('display_name', request.current_user['username']),
        'status': 'draft',  # draft, published, archived
        'version': 1,
        'views': 0,
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'published_at': None,
        'metadata': {}
    }

    result = documents_collection.insert_one(doc)
    doc['_id'] = result.inserted_id

    log_audit(str(request.current_user['_id']), 'document_created', {
        'document_id': str(result.inserted_id),
        'title': title
    })

    return jsonify({
        'message': 'Document created',
        'document': serialize_doc(doc)
    }), 201


@app.route('/api/documents/<doc_id>', methods=['GET'])
@require_auth
def get_document(doc_id):
    """Get a single document by ID."""
    if not validate_object_id(doc_id):
        return jsonify({'error': 'Invalid document ID'}), 400

    doc = documents_collection.find_one({'_id': ObjectId(doc_id)})
    if not doc:
        return jsonify({'error': 'Document not found'}), 404

    # Only published docs visible to viewers, unless author or admin
    user = request.current_user
    if doc['status'] != 'published':
        if user['role'] == 'viewer' and doc['author_id'] != user['_id']:
            return jsonify({'error': 'Document not found'}), 404

    # Increment view count
    documents_collection.update_one(
        {'_id': ObjectId(doc_id)},
        {'$inc': {'views': 1}}
    )

    return jsonify({'document': serialize_doc(doc)}), 200


@app.route('/api/documents', methods=['GET'])
@require_auth
def list_documents():
    """List documents with filtering, searching, and pagination."""
    page = max(1, request.args.get('page', 1, type=int))
    per_page = min(100, max(1, request.args.get('per_page', 20, type=int)))
    skip = (page - 1) * per_page

    query = {}

    # Status filter
    status = sanitize_string(request.args.get('status', ''), max_length=20)
    if status and status in ('draft', 'published', 'archived'):
        query['status'] = status
    elif request.current_user['role'] == 'viewer':
        query['status'] = 'published'

    # Category filter
    category = sanitize_string(request.args.get('category', ''), max_length=50)
    if category:
        query['category'] = category

    # Tag filter
    tag = sanitize_string(request.args.get('tag', ''), max_length=50)
    if tag:
        query['tags'] = tag.lower()

    # Author filter
    author_id = request.args.get('author_id', '')
    if author_id and validate_object_id(author_id):
        query['author_id'] = ObjectId(author_id)

    # Text search
    search = sanitize_string(request.args.get('search', ''), max_length=200)
    if search:
        query['$text'] = {'$search': search}

    # Date range filter
    date_from = request.args.get('date_from', '')
    date_to = request.args.get('date_to', '')
    if date_from or date_to:
        date_query = {}
        try:
            if date_from:
                date_query['$gte'] = datetime.fromisoformat(date_from)
            if date_to:
                date_query['$lte'] = datetime.fromisoformat(date_to)
            if date_query:
                query['created_at'] = date_query
        except ValueError:
            pass

    # Sort
    sort_by = sanitize_string(request.args.get('sort_by', 'created_at'), max_length=20)
    sort_order_str = request.args.get('sort_order', 'desc')
    allowed_sort_fields = {'created_at', 'updated_at', 'title', 'views'}
    if sort_by not in allowed_sort_fields:
        sort_by = 'created_at'
    sort_order = DESCENDING if sort_order_str == 'desc' else ASCENDING

    total = documents_collection.count_documents(query)
    docs = documents_collection.find(query).sort(sort_by, sort_order).skip(skip).limit(per_page)

    return jsonify({
        'documents': [serialize_doc(d) for d in docs],
        'total': total,
        'page': page,
        'per_page': per_page,
        'total_pages': (total + per_page - 1) // per_page
    }), 200


@app.route('/api/documents/<doc_id>', methods=['PUT'])
@require_auth
@require_role('editor', 'admin')
def update_document(doc_id):
    """Update a document."""
    if not validate_object_id(doc_id):
        return jsonify({'error': 'Invalid document ID'}), 400

    doc = documents_collection.find_one({'_id': ObjectId(doc_id)})
    if not doc:
        return jsonify({'error': 'Document not found'}), 404

    # Only author or admin can update
    user = request.current_user
    if doc['author_id'] != user['_id'] and user['role'] != 'admin':
        return jsonify({'error': 'Permission denied'}), 403

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    update_data = {}
    allowed_fields = {'title', 'content', 'category', 'tags', 'status', 'metadata'}

    for field in allowed_fields:
        if field in data:
            if field == 'title':
                val = sanitize_string(data[field], max_length=200)
                if val:
                    update_data[field] = val
            elif field == 'content':
                val = sanitize_string(data[field], max_length=100000)
                if val:
                    update_data[field] = val
            elif field == 'category':
                update_data[field] = sanitize_string(data[field], max_length=50) or ''
            elif field == 'tags':
                if isinstance(data[field], list):
                    update_data[field] = [
                        sanitize_string(str(t), max_length=50).lower()
                        for t in data[field][:20]
                        if sanitize_string(str(t), max_length=50)
                    ]
            elif field == 'status':
                new_status = sanitize_string(data[field], max_length=20)
                if new_status in ('draft', 'published', 'archived'):
                    update_data[field] = new_status
                    if new_status == 'published' and doc['status'] != 'published':
                        update_data['published_at'] = datetime.utcnow()
            elif field == 'metadata':
                if isinstance(data[field], dict):
                    try:
                        sanitize_query_value(data[field])
                        update_data[field] = data[field]
                    except ValueError as e:
                        return jsonify({'error': str(e)}), 400

    if not update_data:
        return jsonify({'error': 'No valid fields to update'}), 400

    update_data['updated_at'] = datetime.utcnow()

    documents_collection.update_one(
        {'_id': ObjectId(doc_id)},
        {
            '$set': update_data,
            '$inc': {'version': 1}
        }
    )

    updated_doc = documents_collection.find_one({'_id': ObjectId(doc_id)})
    log_audit(str(user['_id']), 'document_updated', {
        'document_id': doc_id,
        'fields': list(update_data.keys())
    })

    return jsonify({
        'message': 'Document updated',
        'document': serialize_doc(updated_doc)
    }), 200


