@app.route('/api/analytics/documents-by-status', methods=['GET'])
@require_auth
@require_role('editor', 'admin')
def documents_by_status():
    """Aggregate documents grouped by status."""
    pipeline = [
        {
            '$group': {
                '_id': '$status',
                'count': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'avg_views': {'$avg': '$views'}
            }
        },
        {
            '$project': {
                'status': '$_id',
                '_id': 0,
                'count': 1,
                'total_views': 1,
                'avg_views': {'$round': ['$avg_views', 2]}
            }
        },
        {'$sort': {'count': -1}}
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'analytics': results}), 200


@app.route('/api/analytics/documents-by-category', methods=['GET'])
@require_auth
@require_role('editor', 'admin')
def documents_by_category():
    """Aggregate documents grouped by category."""
    pipeline = [
        {
            '$group': {
                '_id': '$category',
                'count': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'published_count': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                }
            }
        },
        {
            '$project': {
                'category': {'$ifNull': ['$_id', 'Uncategorized']},
                '_id': 0,
                'count': 1,
                'total_views': 1,
                'published_count': 1
            }
        },
        {'$sort': {'count': -1}}
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'analytics': results}), 200


@app.route('/api/analytics/top-authors', methods=['GET'])
@require_auth
@require_role('editor', 'admin')
def top_authors():
    """Get top authors by document count and views."""
    limit = min(50, max(1, request.args.get('limit', 10, type=int)))

    pipeline = [
        {
            '$group': {
                '_id': '$author_id',
                'author_name': {'$first': '$author_name'},
                'document_count': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'published_count': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                },
                'categories': {'$addToSet': '$category'}
            }
        },
        {
            '$lookup': {
                'from': 'users',
                'localField': '_id',
                'foreignField': '_id',
                'as': 'user_info'
            }
        },
        {
            '$project': {
                'author_id': {'$toString': '$_id'},
                '_id': 0,
                'author_name': 1,
                'document_count': 1,
                'total_views': 1,
                'published_count': 1,
                'categories': 1,
                'email': {'$arrayElemAt': ['$user_info.email', 0]}
            }
        },
        {'$sort': {'total_views': -1}},
        {'$limit': limit}
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'top_authors': results}), 200


@app.route('/api/analytics/popular-tags', methods=['GET'])
@require_auth
def popular_tags():
    """Get most popular tags."""
    limit = min(100, max(1, request.args.get('limit', 20, type=int)))

    pipeline = [
        {'$match': {'status': 'published'}},
        {'$unwind': '$tags'},
        {
            '$group': {
                '_id': '$tags',
                'count': {'$sum': 1},
                'total_views': {'$sum': '$views'}
            }
        },
        {
            '$project': {
                'tag': '$_id',
                '_id': 0,
                'count': 1,
                'total_views': 1
            }
        },
        {'$sort': {'count': -1}},
        {'$limit': limit}
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'popular_tags': results}), 200


@app.route('/api/analytics/content-timeline', methods=['GET'])
@require_auth
@require_role('editor', 'admin')
def content_timeline():
    """Aggregate document creation over time (by month)."""
    months = min(24, max(1, request.args.get('months', 12, type=int)))
    start_date = datetime.utcnow() - timedelta(days=months * 30)

    pipeline = [
        {'$match': {'created_at': {'$gte': start_date}}},
        {
            '$group': {
                '_id': {
                    'year': {'$year': '$created_at'},
                    'month': {'$month': '$created_at'}
                },
                'count': {'$sum': 1},
                'published': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                },
                'total_views': {'$sum': '$views'}
            }
        },
        {
            '$project': {
                '_id': 0,
                'year': '$_id.year',
                'month': '$_id.month',
                'count': 1,
                'published': 1,
                'total_views': 1
            }
        },
        {'$sort': {'year': 1, 'month': 1}}
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'timeline': results}), 200


@app.route('/api/analytics/author-activity', methods=['GET'])
@require_auth
@require_role('admin')
def author_activity():
    """Detailed author activity aggregation with facets."""
    pipeline = [
        {
            '$facet': {
                'by_status': [
                    {
                        '$group': {
                            '_id': {'author_id': '$author_id', 'status': '$status'},
                            'count': {'$sum': 1}
                        }
                    }
                ],
                'most_viewed': [
                    {'$sort': {'views': -1}},
                    {'$limit': 10},
                    {
                        '$project': {
                            'title': 1,
                            'author_name': 1,
                            'views': 1,
                            'status': 1,
                            'created_at': 1,
                            '_id': {'$toString': '$_id'}
                        }
                    }
                ],
                'recent_activity': [
                    {'$sort': {'updated_at': -1}},
                    {'$limit': 10},
                    {
                        '$project': {
                            'title': 1,
                            'author_name': 1,
                            'status': 1,
                            'updated_at': 1,
                            '_id': {'$toString': '$_id'}
                        }
                    }
                ],
                'overall_stats': [
                    {
                        '$group': {
                            '_id': None,
                            'total_documents': {'$sum': 1},
                            'total_views': {'$sum': '$views'},
                            'avg_views': {'$avg': '$views'},
                            'unique_authors': {'$addToSet': '$author_id'},
                            'unique_categories': {'$addToSet': '$category'}
                        }
                    },
                    {
                        '$project': {
                            '_id': 0,
                            'total_documents': 1,
                            'total_views': 1,
                            'avg_views': {'$round': ['$avg_views', 2]},
                            'unique_authors_count': {'$size': '$unique_authors'},
                            'unique_categories_count': {'$size': '$unique_categories'}
                        }
                    }
                ]
            }
        }
    ]

    results = list(documents_collection.aggregate(pipeline))
    if results:
        result = results[0]
        # Serialize ObjectIds in by_status
        for item in result.get('by_status', []):
            if '_id' in item and 'author_id' in item['_id']:
                item['_id']['author_id'] = str(item['_id']['author_id'])
        # Serialize dates in recent_activity and most_viewed
        for item in result.get('recent_activity', []):
            if 'updated_at' in item and isinstance(item['updated_at'], datetime):
                item['updated_at'] = item['updated_at'].isoformat()
        for item in result.get('most_viewed', []):
            if 'created_at' in item and isinstance(item['created_at'], datetime):
                item['created_at'] = item['created_at'].isoformat()
        return jsonify({'activity': result}), 200

    return jsonify({'activity': {}}), 200


@app.route('/api/analytics/dashboard', methods=['GET'])
@require_auth
@require_role('editor', 'admin')
def dashboard_stats():
    """Dashboard summary statistics."""
    user = request.current_user

    # Base query for editors (own docs) vs admins (all docs)
    match_stage = {}
    if user['role'] == 'editor':
        match_stage = {'author_id': user['_id']}

    pipeline = [
        {'$match': match_stage} if match_stage else {'$match': {}},
        {
            '$group': {
                '_id': None,
                'total_documents': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'draft_count': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'draft']}, 1, 0]}
                },
                'published_count': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                },
                'archived_count': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'archived']}, 1, 0]}
                }
            }
        },
        {
            '$project': {
                '_id': 0,
                'total_documents': 1,
                'total_views': 1,
                'draft_count': 1,
                'published_count': 1,
                'archived_count': 1
            }
        }
    ]

    results = list(documents_collection.aggregate(pipeline))
    stats = results[0] if results else {
        'total_documents': 0,
        'total_views': 0,
        'draft_count': 0,
        'published_count': 0,
        'archived_count': 0
    }

    # Add user count for admins
    if user['role'] == 'admin':
        stats['total_users'] = users_collection.count_documents({})
        stats['active_users'] = users_collection.count_documents({'is_active': True})

    return jsonify({'dashboard': stats}), 200


# ==================== AUDIT LOG ENDPOINTS ====================

@app.route('/api/audit-log', methods=['GET'])
@require_auth
@require_role('admin')
def get_audit_log():
    """Get audit log entries (admin only)."""
    page = max(1, request.args.get('page', 1, type=int))
    per_page = min(100, max(1, request.args.get('per_page', 50, type=int)))
    skip = (page - 1) * per_page

    query = {}
    action = sanitize_string(request.args.get('action', ''), max_length=50)
    if action:
        query['action'] = action

    user_id = request.args.get('user_id', '')
    if user_id and validate_object_id(user_id):
        query['user_id'] = user_id

    total = audit_log_collection.count_documents(query)
    logs = audit_log_collection.find(query).sort('timestamp', DESCENDING).skip(skip).limit(per_page)

    return jsonify({
        'audit_log': [serialize_doc(log) for log in logs],
        'total': total,
        'page': page,
        'per_page': per_page
    }), 200


# ==================== HEALTH CHECK ====================

@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint."""
    try:
        client.admin.command('ping')
        db_status = 'connected'
    except Exception:
        db_status = 'disconnected'

    return jsonify({
        'status': 'healthy' if db_status == 'connected' else 'unhealthy',
        'database': db_status,
        'timestamp': datetime.utcnow().isoformat()
    }), 200 if db_status == 'connected' else 503


